@ParameterizedTest
//           Input Message              Expected messages
@CsvSource({"[messageId]-13.mxml,       [messageId]-14.mxml, [messageId]-16.mxml"})
public void WholeFlow_LogError_Test(
        String inputMXMLName,
        String output1ExpectedMXMLName,
        String errorOutputExpectedMXMLName) throws TestException {

    SpyObjectReference inputRef   = new SpyObjectReference()
            .application("[AppName]").messageFlow("[FlowName]").node("[InputNode]");
    SpyObjectReference output1Ref = new SpyObjectReference()
            .application("[AppName]").messageFlow("[FlowName]").node("[OutputNode1]");
    SpyObjectReference errorRef   = new SpyObjectReference()
            .application("[AppName]").messageFlow("[FlowName]").node("[ErrorOutputNode]");

    NodeSpy inputSpy   = new NodeSpy(inputRef);
    NodeSpy output1Spy = new NodeSpy(output1Ref);
    NodeSpy errorSpy   = new NodeSpy(errorRef);

    output1Spy.setStopAtInputTerminal("in");
    errorSpy.setStopAtInputTerminal("in");

    TestMessageAssembly inputAssembly = new TestMessageAssembly();
    inputAssembly.buildFromRecordedMessageAssembly(
            Thread.currentThread().getContextClassLoader().getResourceAsStream(inputMXMLName));

    inputSpy.propagate(inputAssembly, "catch");   // drive the error path

    TestMessageAssembly actualOutput1 = output1Spy.receivedMessageAssembly("in", 1);
    TestMessageAssembly actualError   = errorSpy.receivedMessageAssembly("in", 1);

    TestMessageAssembly expectedOutput1 = new TestMessageAssembly();
    expectedOutput1.buildFromRecordedMessageAssembly(
            Thread.currentThread().getContextClassLoader().getResourceAsStream(output1ExpectedMXMLName));
    TestMessageAssembly expectedError = new TestMessageAssembly();
    expectedError.buildFromRecordedMessageAssembly(
            Thread.currentThread().getContextClassLoader().getResourceAsStream(errorOutputExpectedMXMLName));

    assertThat(actualOutput1, equalsMessage(expectedOutput1));
    assertThat(actualError,   equalsMessage(expectedError));
}

