pattern.code:
@ParameterizedTest
//           File name                   BranchA?  BranchB?  BranchC?
@CsvSource({"[filename1].json,              1,        0,        0",
            "[filename2].json,              0,        1,        0",
            "[filename3].json,              0,        0,        0"})
void [FlowName]_RoutingTest(String fileName, int branchA, int branchB, int branchC)
        throws TestException {

    // Spy on the input node to inject the message
    SpyObjectReference inputRef = new SpyObjectReference()
            .application("[AppName]").messageFlow("[FlowName]").node("[InputNodeLabel]");
    NodeSpy inputSpy = new NodeSpy(inputRef);

    // Stub external-call nodes to prevent real I/O — propagatesInputMessage lets
    // the flow continue past the stub so downstream routing can still be evaluated
    SpyObjectReference externalRef = new SpyObjectReference()
            .application("[AppName]").messageFlow("[FlowName]").node("[ExternalNodeLabel]");
    NodeStub externalStub = new NodeStub(externalRef);
    externalStub.onCall().propagatesInputMessage("in", "out");

    // Stub the branch nodes being asserted — propagate through so counts accumulate
    SpyObjectReference branchARef = new SpyObjectReference()
            .application("[AppName]").messageFlow("[FlowName]").node("[BranchANodeLabel]");
    NodeStub branchAStub = new NodeStub(branchARef);
    branchAStub.onCall().propagatesInputMessage("in", "out");

    SpyObjectReference branchBRef = new SpyObjectReference()
            .application("[AppName]").messageFlow("[FlowName]").node("[BranchBNodeLabel]");
    NodeStub branchBStub = new NodeStub(branchBRef);
    branchBStub.onCall().propagatesInputMessage("in", "out");

    SpyObjectReference branchCRef = new SpyObjectReference()
            .application("[AppName]").messageFlow("[FlowName]").node("[BranchCNodeLabel]");
    NodeStub branchCStub = new NodeStub(branchCRef);
    branchCStub.onCall().propagatesInputMessage("in", "out");

    // Build input from a raw file — no .mxml recording required
    TestMessageAssembly input = new TestMessageAssembly();
    input.buildBLOBMessage(Thread.currentThread().getContextClassLoader()
            .getResourceAsStream("/[ResourceSubDir]/" + fileName));

    // Seed any LocalEnvironment values the flow reads during execution
    input.localEnvironmentPath("[testControlAttribute]").setValue([defaultValue]);

    // Drive the flow
    inputSpy.propagate(input, "out");

    // Assert each branch was (or was not) reached the expected number of times
    assertThat(branchAStub, terminalReceiveCountIs("in", branchA));
    assertThat(branchBStub, terminalReceiveCountIs("in", branchB));
    assertThat(branchCStub, terminalReceiveCountIs("in", branchC));
}

import java.io.IOException;
import java.nio.file.*;
import java.util.*;
import java.util.stream.Stream;
import org.junit.jupiter.params.provider.Arguments;
import org.junit.jupiter.params.provider.MethodSource;

class [FlowName]_Routing_[NNNN] {

    /**
     * Scans a named subdirectory under the deployed test project resources folder
     * and returns one Arguments entry per .json file found.
     * Called by @MethodSource on each path-specific test method.
     */
    public static List<Arguments> scanResourcesForTestFiles(String directoryName) throws Exception {
        List<Arguments> results = new ArrayList<>();
        String serverWorkDir = System.getProperty("broker.workdir");
        String testProject   = System.getProperty("broker.testProject");
        Path dir = Paths.get(serverWorkDir, "run", testProject, "resources", directoryName);

        try (Stream<Path> stream = Files.walk(dir)) {
            stream.filter(Files::isRegularFile)
                  .forEach(path -> {
                      if (path.getFileName().toString().endsWith(".json")) {
                          results.add(Arguments.of(directoryName + "/" + path.getFileName()));
                      }
                  });
        } catch (IOException e) { throw e; }

        if (results.isEmpty()) {
            throw new Exception("No JSON files found in " + dir);
        }
        return results;
    }

    // One @MethodSource method + @ParameterizedTest per expected routing outcome:
    public static List<Arguments> scanFor[BranchA]Files() throws Exception {
        return scanResourcesForTestFiles("[BranchATestFiles]");
    }
    @ParameterizedTest
    @MethodSource("scanFor[BranchA]Files")
    void [BranchA]RoutingTest(String fileName) throws TestException {
        commonRoutingTest(fileName, 1 /* branchA */, 0 /* branchB */);
    }

    public static List<Arguments> scanFor[BranchB]Files() throws Exception {
        return scanResourcesForTestFiles("[BranchBTestFiles]");
    }
    @ParameterizedTest
    @MethodSource("scanFor[BranchB]Files")
    void [BranchB]RoutingTest(String fileName) throws TestException {
        commonRoutingTest(fileName, 0 /* branchA */, 1 /* branchB */);
    }

    /** Shared test logic — wires stubs and drives the flow */
    void commonRoutingTest(String fileName, int branchA, int branchB) throws TestException {
        SpyObjectReference inputRef = new SpyObjectReference()
                .application("[AppName]").messageFlow("[FlowName]").node("[InputNodeLabel]");
        NodeSpy inputSpy = new NodeSpy(inputRef);

        SpyObjectReference branchARef = new SpyObjectReference()
                .application("[AppName]").messageFlow("[FlowName]").node("[BranchANodeLabel]");
        NodeStub branchAStub = new NodeStub(branchARef);
        branchAStub.onCall().propagatesInputMessage("in", "out");

        SpyObjectReference branchBRef = new SpyObjectReference()
                .application("[AppName]").messageFlow("[FlowName]").node("[BranchBNodeLabel]");
        NodeStub branchBStub = new NodeStub(branchBRef);
        branchBStub.onCall().propagatesInputMessage("in", "out");

        TestMessageAssembly input = new TestMessageAssembly();
        input.buildBLOBMessage(Thread.currentThread().getContextClassLoader()
                .getResourceAsStream("/" + fileName));
        input.localEnvironmentPath("[testControlAttribute]").setValue([defaultValue]);

        inputSpy.propagate(input, "out");

        assertThat(branchAStub, terminalReceiveCountIs("in", branchA));
        assertThat(branchBStub, terminalReceiveCountIs("in", branchB));
    }
}

import static org.junit.jupiter.api.Assertions.*;

@Test
void [ScenarioDescription]_ThrowsExpectedError() throws TestException {

    SpyObjectReference inputRef = new SpyObjectReference()
            .application("[AppName]").messageFlow("[FlowName]").node("[InputNodeLabel]");
    NodeSpy inputSpy = new NodeSpy(inputRef);

    SpyObjectReference observedRef = new SpyObjectReference()
            .application("[AppName]").messageFlow("[FlowName]").node("[ObservedNodeLabel]");
    NodeSpy observedSpy = new NodeSpy(observedRef);

    TestMessageAssembly input = new TestMessageAssembly();
    input.buildBLOBMessage(Thread.currentThread().getContextClassLoader()
            .getResourceAsStream("/[ResourceSubDir]/[filename].[ext]"));

    // Seed Environment/LocalEnvironment flags that trigger the failure condition
    input.environmentPath("Variables.[flagName]").setValue("[triggerValue]");
    input.localEnvironmentPath("[testControlAttribute]").setValue("[value]");

    // Assert the flow throws — capture the exception to inspect the BIP number
    TestException ex = assertThrows(TestException.class,
            () -> inputSpy.propagate(input, "out"));
    assertEquals([expectedBIPNumber], ex.getMessageNumber());

    // Assert node counts reflect the partial execution before the failure
    assertThat(observedSpy, terminalPropagateCountIs("out", 0));

    // --- Second propagation in the same test (different control value) ---
    // Spy counts are CUMULATIVE within a test — factor previous counts in
    input.localEnvironmentPath("[testControlAttribute]").setValue("[differentValue]");
    TestException ex2 = assertThrows(TestException.class,
            () -> inputSpy.propagate(input, "out"));
    assertEquals([expectedBIPNumber], ex2.getMessageNumber());

    // Count includes BOTH propagations
    assertThat(observedSpy, terminalPropagateCountIs("[OutputTerminal]", [cumulativeCount]));
}
